#include <bits/stdc++.h>
using namespace std;

const int N=1010;

int c,T,n,m,s,k,a[N][N],f[N][N];

int main(){
    scanf("%d%d",&c,&T);
    while(T--){
        scanf("%d%d%d%d",&n,&m,&s,&k);
        for(int i=1;i<=n;i++)
            for(int j=1;j<=m;j++)
                scanf("%d",&a[i][j]);
        memset(f,0xcf,sizeof(f));
        for(int i=1;i<=m;i++)
            f[0][i]=s;
        for(int i=1;i<=n;i++){
            for(int j=1;j<=m;j++)
                if(f[i-1][j]>=0)
                    f[i][j]=min(k,f[i-1][j]+a[i][j]);
            if(i==n)
                break;
            for(int j=2;j<=m;j++)
                if(f[i][j-1]>=0 && min(k,f[i][j-1]+a[i][j])>max(-1,f[i][j]))
                    f[i][j]=min(k,f[i][j-1]+a[i][j]);
            for(int j=m-1;j;j--)
                if(f[i][j+1]>=0 && min(k,f[i][j+1]+a[i][j])>max(-1,f[i][j]))
                    f[i][j]=min(k,f[i][j+1]+a[i][j]);
            for(int j=2;j<=m;j++)
                if(f[i][j-1]>=0 && min(k,f[i][j-1]+a[i][j])>max(-1,f[i][j])){
                    if(a[i][j]>=0)
                        f[i][j]=k;
                    else
                        f[i][j]=min(k,f[i][j-1]+a[i][j]);
                }
            for(int j=m-1;j;j--)
                if(f[i][j+1]>=0 && min(k,f[i][j+1]+a[i][j])>max(-1,f[i][j])){
                    if(a[i][j]>=0)
                        f[i][j]=k;
                    else
                        f[i][j]=min(k,f[i][j+1]+a[i][j]);
                }
            for(int j=2;j<=m;j++)
                if(f[i][j-1]>=0 && min(k,f[i][j-1]+a[i][j])>max(-1,f[i][j]))
                    f[i][j]=min(k,f[i][j-1]+a[i][j]);
            for(int j=m-1;j;j--)
                if(f[i][j+1]>=0 && min(k,f[i][j+1]+a[i][j])>max(-1,f[i][j]))
                    f[i][j]=min(k,f[i][j+1]+a[i][j]);
            //for(int j=1;j<=m;j++)
            //    printf("%d ",f[i][j]);
            //puts("");
        }
        int ans=-1;
        for(int i=1;i<=m;i++)
            ans=max(ans,f[n][i]);
        printf("%d\n",ans);
    }
    return 0;
}
